if ($this->totalSelectedRecordsCount > $this->successfulSelectedRecordsCount) {
    foreach ($authorizationResponses as $responseKey => $response) {
        if ($response instanceof DenyResponse) {
            $failureMessages[] = $response->message($failureCountsByAuthorizationResponse[$responseKey], $this->totalSelectedRecordsCount);
        } else {
            $failureMessages[] = $response;
        }
    }
}

if ($checkActionUsing) {
    Assert::assertFalse(
        $checkActionUsing($action),
        $generateMessageUsing ?
            $generateMessageUsing($prettyName, $livewireClass) :
            "Failed asserting that an action with the name [{$prettyName}] and provided configuration does not exist on the [{$livewireClass}] component.",
    );
} else {
    Assert::assertNotInstanceOf(
        Action::class,
        $action,
        $generateMessageUsing ?
            $generateMessageUsing($prettyName, $livewireClass) :
            "Failed asserting that an action with the name [{$prettyName}] does not exist on the [{$livewireClass}] component.",
    );
}

if ($component->hasOptionDescriptionFromRecordUsingCallback()) {
    $descriptions = $records
        ->mapWithKeys(static fn (Model $record) => [
            $record->{Str::afterLast($relationship->getQualifiedRelatedKeyName(), '.')} => $component->getOptionDescriptionFromRecord($record),
        ])
        ->toArray();

    $component->descriptions($descriptions);
}

if (is_array($state)) {
    collect($repeaterSiblingState)
        ->filter(fn (array $itemState): bool => filled(array_intersect(data_get($itemState, $componentItemStatePath, []), $state)))
        ->map(fn (array $itemState): array => collect(data_get($itemState, $componentItemStatePath) ?? [])
            ->diff($state)
            ->values()
            ->all())
        ->each(fn (array $newSiblingItemState, string $itemKey) => $set(
            path: "{$repeaterStatePath}.{$itemKey}.{$componentItemStatePath}",
            state: $newSiblingItemState,
            isAbsolute: true,
        ));

    return;
}

if (
    blank($descriptions) &&
    filled($enum = $this->getEnum()) &&
    is_a($enum, HasDescription::class, allow_string: true)
) {
    $descriptions = array_reduce($enum::cases(), function (array $carry, HasDescription & UnitEnum $case): array {
        if (filled($description = $case->getDescription())) {
            $carry[$case->value ?? $case->name] = $description;
        }

        return $carry;
    }, []);
}

if (filled($defaultFocusedDate)) {
    if (! $defaultFocusedDate instanceof CarbonInterface) {
        try {
            $defaultFocusedDate = Carbon::createFromFormat($this->getFormat(), (string) $defaultFocusedDate, config('app.timezone'));
        } catch (InvalidFormatException $exception) {
            try {
                $defaultFocusedDate = Carbon::parse($defaultFocusedDate, config('app.timezone'));
            } catch (InvalidFormatException $exception) {
                return null;
            }
        }
    }

    $defaultFocusedDate = $defaultFocusedDate->setTimezone($this->getTimezone());
}

if (! $defaultFocusedDate instanceof CarbonInterface) {
    try {
        $defaultFocusedDate = Carbon::createFromFormat($this->getFormat(), (string) $defaultFocusedDate, config('app.timezone'));
    } catch (InvalidFormatException $exception) {
        try {
            $defaultFocusedDate = Carbon::parse($defaultFocusedDate, config('app.timezone'));
        } catch (InvalidFormatException $exception) {
            return null;
        }
    }
}

foreach ($this->customBlocks as $key => $block) {
    if (is_string($key) && is_a($key, RichContentCustomBlock::class, allow_string: true)) {
        // Data association: `BlockClass::class => $data`
        $blocks[] = $key;
    } elseif (is_array($block)) {
        // Group or ungrouped section: `'Label' => [...]` or `[...]`
        foreach ($block as $innerKey => $innerValue) {
            $blocks[] = is_string($innerKey) ? $innerKey : $innerValue;
        }
    } else {
        $blocks[] = $block;
    }
}

foreach ($actions as $actionNestingIndex => $action) {
    $component = $components[$actionNestingIndex] ?? null;

    if (blank($component)) {
        continue;
    }

    if (! $actionNestingIndex) {
        $component = "{$form}.{$component}";
    }

    $action['context']['schemaComponent'] = $component;

    $actions[$actionNestingIndex] = $action;
}

if (filled($tenantDomain)) {
    $routeGroup->domain($tenantDomain);
} else {
    $routeGroup->prefix(
        (
            filled($tenantRoutePrefix) ?
                "{$tenantRoutePrefix}/" :
                ''
        ) . '{tenant' . (
            filled($tenantSlugAttribute) ?
                ":{$tenantSlugAttribute}" :
                ''
        ) . '}',
    );
}

class UiAvatarsProvider implements Contracts\AvatarProvider
{
    public function get(Model | Authenticatable $record): string
    {
        $name = str(Filament::getNameForDefaultAvatar($record))
            ->trim()
            ->explode(' ')
            ->map(fn (string $segment): string => filled($segment) ? mb_substr($segment, 0, 1) : '')
            ->join(' ');

        $background = Color::convertToHex(FilamentColor::getColor('gray')[950] ?? Color::Gray[950]);

        return 'https://ui-avatars.com/api/?name=' . urlencode($name) . '&format=svg&color=FFFFFF&background=' . urlencode($background);
    }
}

if (
    class_exists($resourceModelFqn) &&
    method_exists($resourceModelFqn, $this->relationship) &&
    (($relationshipInstance = app($resourceModelFqn)->{$this->relationship}()) instanceof Relation) &&
    class_exists($relationshipInstance->getRelated()::class) &&
    in_array($relationshipInstance::class, [
        HasMany::class,
        BelongsToMany::class,
        MorphMany::class,
        MorphToMany::class,
    ])
) {
    $this->relationshipType = $relationshipInstance::class;

    return;
}

if ($pluralParentResourceBasenameBeforeResource === $parentResourceNamespacePartBeforeBasename) {
    $this->resourcesNamespace = (string) str($this->parentResourceFqn)
        ->beforeLast('\\')
        ->append('\\Resources');
    $this->resourcesDirectory = (string) str((new ReflectionClass($this->parentResourceFqn))->getFileName())
        ->beforeLast(DIRECTORY_SEPARATOR)
        ->append('/Resources');

    return;
}

if (str_contains($trailingWhitespace, "\n")) {
    // Extract the indentation from existing array entries (look for newline followed by spaces and a quote)
    preg_match('/\n(\s+)[\'"]/', $inputArrayContents, $indentMatch);
    $indent = $indentMatch[1] ?? '            ';
    $newInputArrayContents = $beforeTrailing . ",\n{$indent}{$newEntry}," . $trailingWhitespace;
} else {
    // Single line - just append with comma
    $newInputArrayContents = $beforeTrailing . ", {$newEntry}" . $trailingWhitespace;
}

foreach ($resource::getRelations() as $relation) {
    if ($relation instanceof RelationGroup) {
        foreach ($relation->getManagers() as $groupedRelation) {
            $this->queueLivewireComponentForRegistration($this->normalizeRelationManagerClass($groupedRelation));
        }

        continue;
    }

    $this->queueLivewireComponentForRegistration($this->normalizeRelationManagerClass($relation));
}

if ($record->exists && $resource::hasRecordTitle()) {
    if ($resource::hasPage('view') && $resource::canView($record)) {
        $breadcrumbs[
            $this->getResourceUrl('view')
        ] = $this->getRecordTitle();
    } elseif ($resource::hasPage('edit') && $resource::canEdit($record)) {
        $breadcrumbs[
            $this->getResourceUrl('edit')
        ] = $this->getRecordTitle();
    } else {
        $breadcrumbs[] = $this->getRecordTitle();
    }
}

if ($parentResource = static::getParentResourceRegistration()) {
    $parentResource->getParentResource()::registerRoutes($panel, function () use ($panel, $parentResource, $registerPageRoutes): void {
        Route::name($parentResource->getRouteName() . '.')
            ->prefix('{' . $parentResource->getParentRouteParameterName() . '}/' . static::getSlug($panel))
            ->group($registerPageRoutes);
    });

    return;
}

if (array_key_exists($key, $components)) {
    Assert::assertEquals(
        $value,
        $components[$key]->getState(),
        "Failed asserting that a component [{$key}] has the expected state in the [{$schema}] schema on the [{$livewireClass}] component."
    );
} else {
    $this->assertSet((filled($schemaStatePath) ? "{$schemaStatePath}." : '') . $key, $value);
}

if ($hasBootstrapProvidersFile) {
    ServiceProvider::addProviderToBootstrapFile(
        $fqn,
        $bootstrapProvidersPath,
    );
} else {
    $appConfig = file_get_contents(config_path('app.php'));

    if (! Str::contains($appConfig, "{$fqn}::class")) {
        file_put_contents(config_path('app.php'), str_replace(
            app()->getNamespace() . 'Providers\\RouteServiceProvider::class,',
            "{$fqn}::class," . PHP_EOL . '        ' . app()->getNamespace() . 'Providers\\RouteServiceProvider::class,',
            $appConfig,
        ));
    }
}

if (is_string($initialValue)) {
    $cluster = (string) str($initialValue)
        ->trim('/')
        ->trim('\\')
        ->trim(' ')
        ->replace('/', '\\');

    if (! class_exists($cluster)) {
        $this->components->warn('The cluster class provided does not exist.');
    } elseif (! is_subclass_of($cluster, Cluster::class)) {
        $this->components->warn('The cluster class or one of its parents must extend [' . Cluster::class . '].');
    } else {
        return $cluster;
    }
}

foreach ($this->tableColumns as $item) {
    if ($item['type'] === self::TABLE_COLUMN_MANAGER_COLUMN_TYPE && $item['name'] === $name) {
        return ! $item['isToggled'];
    }

    if ($item['type'] === self::TABLE_COLUMN_MANAGER_GROUP_TYPE && isset($item['columns'])) {
        foreach ($item['columns'] as $column) {
            if ($column['name'] === $name) {
                return ! $column['isToggled'];
            }
        }
    }
}

if ($filter->isMultiple()) {
    $data = ['values' => array_map(
        fn ($data) => $data instanceof Model ? $data->getKey() : ($data instanceof BackedEnum ? $data->value : $data),
        Arr::wrap($data ?? []),
    )];
} else {
    $data = ['value' => $data instanceof Model ? $data->getKey() : ($data instanceof BackedEnum ? $data->value : $data)];
}

foreach (Arr::wrap($job) as $job) {
    if ($job instanceof PendingBatch || $job instanceof Closure) {
        return;
    }

    if (! (static::$batchableClasses[$job::class] ?? false) && ! isset(class_uses_recursive($job)[Batchable::class])) {
        static::$batchableClasses[$job::class] = false;

        throw new RuntimeException(sprintf('Attempted to batch job [%s], but it does not use the Batchable trait.', $job::class));
    }

    static::$batchableClasses[$job::class] = true;
}

if ($source instanceof Closure || $source instanceof self) {
    $this->source = $source;
} elseif (is_null($source)) {
    $this->source = static::empty();
} elseif ($source instanceof Generator) {
    throw new InvalidArgumentException(
        'Generators should not be passed directly to LazyCollection. Instead, pass a generator function.'
    );
} else {
    $this->source = $this->getArrayableItems($source);
}

foreach ($types as $type) {
    $query->orWhere(function ($query) use ($relation, $callback, $operator, $count, $type) {
        $belongsTo = $this->getBelongsToRelation($relation, $type);

        if ($callback) {
            $callback = function ($query) use ($callback, $type) {
                return $callback($query, $type);
            };
        }

        $query->where($this->qualifyColumn($relation->getMorphType()), '=', (new $type)->getMorphClass())
            ->whereHas($belongsTo, $callback, $operator, $count);
    });
}

if (! is_null($columns)) {
    foreach ($columns as $key => $column) {
        $aggregatedColumn = $subQuery->getQuery()->grammar->wrap($subQuery->qualifyColumn($column));

        if ($key === 0) {
            $aggregatedColumn = "{$aggregate}({$aggregatedColumn})";
        } else {
            $aggregatedColumn = "min({$aggregatedColumn})";
        }

        $subQuery->selectRaw($aggregatedColumn.' as '.$subQuery->getQuery()->grammar->wrap($column.'_aggregate'));
    }
}

foreach ($models as $key => $model) {
    if ($model->{$this->morphType}) {
        $morphTypeKey = $this->getDictionaryKey($model->{$this->morphType});
        $foreignKeyKey = $this->getDictionaryKey($model->{$this->foreignKey});

        if ($morphTypeKey === null || $foreignKeyKey === null) {
            continue;
        }

        if ($isAssociative) {
            $this->dictionary[$morphTypeKey][$foreignKeyKey][$key] = $model;
        } else {
            $this->dictionary[$morphTypeKey][$foreignKeyKey][] = $model;
        }
    }
}

if (! $key && $this->input->isInteractive()) {
    $ask = select(
        label: 'What encryption key would you like to use?',
        options: [
            'generate' => 'Generate a random encryption key',
            'ask' => 'Provide an encryption key',
        ],
        default: 'generate'
    );

    if ($ask == 'ask') {
        $key = password('What is the encryption key?');
    }
}

foreach ($rawListeners as $rawListener) {
    if (is_string($rawListener)) {
        $events[$event][] = $this->appendListenerInterfaces($rawListener);
    } elseif ($rawListener instanceof Closure) {
        $events[$event][] = $this->stringifyClosure($rawListener);
    } elseif (is_array($rawListener) && count($rawListener) === 2) {
        if (is_object($rawListener[0])) {
            $rawListener[0] = get_class($rawListener[0]);
        }

        $events[$event][] = $this->appendListenerInterfaces(implode('@', $rawListener));
    }
}
